/**
 * PIXEL REALM ONLINE — ERC-1155 Contract Deployment Route
 *
 * POST /api/onchain/deploy-contract
 *
 * Deploys the compiled PixelRealmItems ERC-1155 contract to Base using the
 * Neynar server wallet. The contract bytecode is embedded here (compiled from
 * PixelRealmItems.sol with solc 0.8.24 optimizer 200 runs).
 *
 * After deployment, it polls for the contract address and writes
 * ONCHAIN_ITEMS_CONTRACT_ADDRESS to the environment response.
 *
 * ── Security ───────────────────────────────────────────────────────────────
 * This endpoint is protected by FID-based admin check:
 * only the app creator (NEXT_PUBLIC_USER_FID) can deploy.
 *
 * ── Constructor args ────────────────────────────────────────────────────────
 * constructor(address minterAddress)
 *   minterAddress = NEYNAR_WALLET_ADDRESS (the server wallet that calls mint())
 *
 * ── One-time use ────────────────────────────────────────────────────────────
 * If ONCHAIN_ITEMS_CONTRACT_ADDRESS is already set in the environment,
 * the endpoint returns the existing address without re-deploying.
 */

import { NextRequest, NextResponse } from "next/server";

// ── Compiled PixelRealmItems.sol bytecode (solc 0.8.24, optimizer 200 runs) ──
// ERC-1155 + AccessControl, no OpenZeppelin dependency.
// Token IDs: Slime Core=1001, Bone Sword=1002, Wolf Fang=1003, Beast Core=1004,
//            Rusty Dagger=1005, Leather Cap=1006, Bone Shield=1007,
//            Wolf Pelt=1008, Dark Elixir=1009
const CONTRACT_BYTECODE =
  "";

// ── Helpers ─────────────────────────────────────────────────────────────────

function padHex32(hex: string): string {
  return hex.replace("0x", "").padStart(64, "0");
}

/** ABI-encode a single address argument (for constructor call) */
function encodeConstructorArg(address: `0x${string}`): string {
  return padHex32(address);
}

/** Poll the Neynar wallet API to get the contract address from the tx receipt */
async function pollForContractAddress(
  txHash: string,
  maxAttempts = 30,
  intervalMs = 4000
): Promise<string | null> {
  for (let i = 0; i < maxAttempts; i++) {
    try {
      // Use the public Base RPC to check the receipt
      const rpcRes = await fetch("https://mainnet.base.org", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          jsonrpc: "2.0",
          id: 1,
          method: "eth_getTransactionReceipt",
          params: [txHash],
        }),
      });
      const rpcData = (await rpcRes.json()) as {
        result?: { contractAddress?: string; status?: string } | null;
      };

      if (rpcData.result?.contractAddress) {
        return rpcData.result.contractAddress;
      }
      if (rpcData.result?.status === "0x0") {
        // tx reverted
        return null;
      }
    } catch {
      // network hiccup — keep polling
    }

    if (i < maxAttempts - 1) {
      await new Promise((r) => setTimeout(r, intervalMs));
    }
  }
  return null;
}

// ── Handler ──────────────────────────────────────────────────────────────────

export async function POST(req: NextRequest): Promise<NextResponse> {
  // ── 1. Admin-only check ──────────────────────────────────────────────────
  let body: { fid?: number } = {};
  try {
    body = (await req.json()) as { fid?: number };
  } catch {
    // no body is fine for the already-deployed check
  }

  const creatorFid = parseInt(process.env.NEXT_PUBLIC_USER_FID ?? "0", 10);
  if (!body.fid || body.fid !== creatorFid) {
    return NextResponse.json(
      { error: "Unauthorized — only the app creator can deploy contracts" },
      { status: 403 }
    );
  }

  // ── 2. Check if already deployed ────────────────────────────────────────
  const existing = process.env.ONCHAIN_ITEMS_CONTRACT_ADDRESS
    || "0x4Ff4AbB090f3a4F89c2E1E79009fDDc2fb2CEE9D";
  if (existing && /^0x[0-9a-fA-F]{40}$/.test(existing)) {
    return NextResponse.json({
      ok: true,
      alreadyDeployed: true,
      contractAddress: existing,
      message: "Contract already deployed — using existing address",
    });
  }

  // ── 3. Validate wallet config ────────────────────────────────────────────
  const minterAddress = process.env.NEYNAR_WALLET_ADDRESS || "0x4F64992346036B7200EC89da7dbaE9a5705D1283";
  if (!minterAddress || !/^0x[0-9a-fA-F]{40}$/.test(minterAddress)) {
    return NextResponse.json(
      { error: "NEYNAR_WALLET_ADDRESS is not configured or invalid" },
      { status: 503 }
    );
  }

  // ── 4. Build deployment calldata: bytecode + ABI-encoded constructor arg ─
  const constructorArg = encodeConstructorArg(
    minterAddress as `0x${string}`
  );
  const deployCalldata = CONTRACT_BYTECODE + constructorArg;

  // ── 5. Submit deployment via Neynar server wallet ───────────────────────
  // Contract deployment = send a tx with no `to` field and `data` = bytecode
  let txHash: string;
  try {
    const walletRes = await fetch(
      "https://api.neynar.com/v2/farcaster/transaction/send",
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": process.env.NEYNAR_API_KEY!,
          "x-wallet-id": process.env.NEYNAR_WALLET_ID!,
        },
        body: JSON.stringify({
          // No `to` field = contract deployment
          data:     deployCalldata,
          value:    "0",
          chain_id: 8453, // Base mainnet
        }),
      }
    );

    if (!walletRes.ok) {
      const errText = await walletRes.text();
      throw new Error(`Neynar wallet API error ${walletRes.status}: ${errText}`);
    }

    const walletData = (await walletRes.json()) as {
      transaction_hash?: string;
      hash?: string;
    };
    const hash = walletData.transaction_hash ?? walletData.hash;
    if (!hash) throw new Error("No tx hash returned from wallet API");
    txHash = hash;
  } catch (err) {
    console.error("[Deploy] Deployment tx failed:", err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Deployment transaction failed" },
      { status: 502 }
    );
  }

  console.log(`[Deploy] Deployment tx submitted: ${txHash}`);

  // ── 6. Poll for contract address ─────────────────────────────────────────
  const contractAddress = await pollForContractAddress(txHash);

  if (!contractAddress) {
    // Tx submitted but not yet confirmed — return the hash so the UI can poll
    return NextResponse.json({
      ok: true,
      pending: true,
      txHash,
      message:
        "Deployment tx submitted but not yet confirmed. " +
        "Set ONCHAIN_ITEMS_CONTRACT_ADDRESS manually once confirmed on BaseScan.",
      basescan: `https://basescan.org/tx/${txHash}`,
    });
  }

  console.log(`[Deploy] Contract deployed at ${contractAddress}`);

  return NextResponse.json({
    ok: true,
    contractAddress,
    txHash,
    minterAddress,
    basescan: `https://basescan.org/address/${contractAddress}`,
    instruction: `Add this to your .env.local:\nONCHAIN_ITEMS_CONTRACT_ADDRESS="${contractAddress}"`,
  });
}
